/*	StIntervalTimer.cpp		Stack-based class for measuring elapsed time. Starts measuring when constructed,	allows calls to be made for splits, and 	stops measuring and reports the splits time when destructed.		Copyright ® 2004 	Tom Padula	All Rights Reserved.	Created March 12th, 2004.		*/#import "StIntervalTimer.h"#include <iostream>using namespace std;#if !TARGET_OS_IPHONE//ččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččč// inLeft must be greater than inRight. This is an unsigned type.UnsignedWide UWDifference (UnsignedWide inLeft, UnsignedWide inRight){	if (inLeft.hi < inRight.hi)		{		cerr << "UnsignedWide Difference inLeft < inRight." << endl;		throw;		}	if ((inLeft.hi == inRight.hi) && (inLeft.lo < inRight.lo))		{		cerr << "UnsignedWide Difference inLeft < inRight." << endl;		throw;		}	UnsignedWide aResult;	aResult.hi = inLeft.hi - inRight.hi;	aResult.lo = inLeft.lo - inRight.lo;		if (inLeft.lo < inRight.lo)		// needed to borrow		aResult.hi--;			return (aResult);}#endif//ččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččč// StIntervalTimer public methods: //čččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččStIntervalTimer::StIntervalTimer (std::string inTaskMessage, std::string inEndMessage){	m_endMessage = inEndMessage;	this->Split (inTaskMessage);}//čččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččStIntervalTimer::~StIntervalTimer (){	this->Split (m_endMessage);		// report.	cerr << endl;	cerr << " Wall Time       Split Time     Percentage   Event" << endl;	cerr << "------------    ------------    ----------   -----" << endl;		// Compute the total elapsed time. #if TARGET_OS_IPHONE	CFAbsoluteTime anEndTime = (m_splitMap.rbegin ())->first;	CFAbsoluteTime aStartTime = (m_splitMap.begin ())->first;	CFAbsoluteTime aTotalElapsedTime = anEndTime - aStartTime;#else	UnsignedWide anEndTime = (m_splitMap.rbegin ())->first;	UnsignedWide aStartTime = (m_splitMap.begin ())->first;	UnsignedWide aTotalElapsedTime = UWDifference (anEndTime, aStartTime);#endif		SHumanTime aZeroTime;	cerr << string (aZeroTime) << "	" << string (aZeroTime) << "		--		" << (m_splitMap.begin ())->second << endl;	SSplitMap::iterator anIter = m_splitMap.begin ();	SSplitMap::iterator aLeadIter = anIter;	aLeadIter++;				// can't say aLeadIter = anIter + 1, not random access iters	while (aLeadIter != m_splitMap.end ())		{		this->ReportSplit (anIter, aLeadIter, aTotalElapsedTime);		anIter++;		aLeadIter++;		}    cerr << endl;}//čččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččvoid StIntervalTimer::Split (std::string inSplitEventMessage){#if TARGET_OS_IPHONE	CFAbsoluteTime aNowTime = CFAbsoluteTimeGetCurrent();	m_splitMap.insert (std::map<const CFAbsoluteTime, string>::value_type (aNowTime, inSplitEventMessage));#else	UnsignedWide aNowTime;	Microseconds (&aNowTime);				// Look at the time...	m_splitMap.insert (std::map<const UnsignedWide, string>::value_type (aNowTime, inSplitEventMessage));#endif}//ččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččč// StIntervalTimer private methods://ččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččč#if TARGET_OS_IPHONEvoid StIntervalTimer::ReportSplit (SSplitMap::iterator inFirst,									  SSplitMap::iterator inSecond,									  CFAbsoluteTime inTotalElapsedTime)#elsevoid StIntervalTimer::ReportSplit (SSplitMap::iterator inFirst,									  SSplitMap::iterator inSecond,									  UnsignedWide inTotalElapsedTime)#endif{	// Note: Our human time conversion is good to about 1100 hours, which	// is 41.6 days. If we go over this, we'll throw.		SHumanTime aSecondTime;	SHumanTime aSplitTime;	#if TARGET_OS_IPHONE	CFAbsoluteTime aSecondWall = inSecond->first - m_splitMap.begin ()->first;	CFAbsoluteTime aSplitIntervalTime = inSecond->first - inFirst->first;#else	UnsignedWide aSecondWall = UWDifference (inSecond->first, (m_splitMap.begin ())->first);	UnsignedWide aSplitIntervalTime = UWDifference (inSecond->first, inFirst->first);#endif		aSecondTime = this->GetHumanTime (aSecondWall);	aSplitTime = this->GetHumanTime (aSplitIntervalTime);		// Compute split percentage.#if TARGET_OS_IPHONE	double aPercentage = aSplitIntervalTime / (double) inTotalElapsedTime;#else	double aSplitInterval = aSplitIntervalTime.lo;	double aPercentage = aSplitInterval / (double) (inTotalElapsedTime.lo);#endif	aPercentage *= 100;	int anIntPercentage = lround (aPercentage);		// report. The line format is second time, split time, percentage of total time.	cerr << string (aSecondTime) << "	" << string (aSplitTime) << "		" << anIntPercentage << "%		" << inSecond->second << endl;}//ččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččččč#if TARGET_OS_IPHONESHumanTime StIntervalTimer::GetHumanTime (CFAbsoluteTime inTime)#elseSHumanTime StIntervalTimer::GetHumanTime (UnsignedWide inTime)#endif{	SHumanTime aTime;		// Get elapsed milliseconds. We get 1000 hours of precision here.#if TARGET_OS_IPHONE	aTime.m_milliseconds = inTime * 1000.0;#else	UInt32 aMicros = inTime.lo;	aTime.m_milliseconds = (aMicros / 1000);	if ((aMicros % 1000000) > 500)		// round off properly		aTime.m_milliseconds++;			// Here's where we get the precision up by 1000x.	if (inTime.hi != 0)		{		if (inTime.hi > 1000)			{			cerr << "StIntervalTimer::GetHumanTime: Time too long to convert, > 1000 hours." << endl;			throw;			}					aTime.m_milliseconds += inTime.hi * (0xFFFFFFFF / 1000);		}#endif	// Get seconds	if (aTime.m_milliseconds > 1000)		{		aTime.m_seconds = aTime.m_milliseconds / 1000;		aTime.m_milliseconds = aTime.m_milliseconds % 1000;		}		// Get minutes	if (aTime.m_seconds >= 60)		{		aTime.m_minutes = aTime.m_seconds / 60;		aTime.m_seconds = aTime.m_seconds % 60;		}		// Get hours	if (aTime.m_minutes > 60)		{		aTime.m_hours = aTime.m_minutes / 60;		aTime.m_minutes = aTime.m_minutes % 60;		}	return (aTime);}